switch (true) {
    case 'null' === $lowercaseValue:
        return null;
    case ctype_digit($value):
    case isset($value[1]) && '-' === $value[0] && ctype_digit(substr($value, 1)):
        $raw = $value;
        $cast = (int) $value;

        return self::isOctal($value) ? \intval($value, 8) : (($raw === (string) $cast) ? $cast : $raw);
    case 'true' === $lowercaseValue:
        return true;
    case 'false' === $lowercaseValue:
        return false;
    case isset($value[1]) && '0b' == $value[0].$value[1] && preg_match('/^0b[01]*$/', $value):
        return bindec($value);
    case is_numeric($value):
        return '0x' === $value[0].$value[1] ? hexdec($value) : (float) $value;
    case preg_match('/^0x[0-9a-f]++$/i', $value):
        return hexdec($value);
    case preg_match('/^[+-]?[0-9]+(\.[0-9]+)?$/', $value):
        return (float) $value;
    default:
        return $value;
}

foreach (explode("\n", substr($doc, 3, -2)) as $line) {
    $line = ltrim($line);
    $line = ltrim($line, '*');

    if ('' === $line = trim($line)) {
        if ('' !== $tagName) {
            $tags[$tagName][] = $tagContent;
        }
        $tagName = $tagContent = '';
        continue;
    }

    if ('@' === $line[0]) {
        if ('' !== $tagName) {
            $tags[$tagName][] = $tagContent;
            $tagContent = '';
        }

        if (preg_match('{^@([-a-zA-Z0-9_:]++)(\s|$)}', $line, $m)) {
            $tagName = $m[1];
            $tagContent = str_replace("\t", ' ', ltrim(substr($line, 2 + \strlen($tagName))));
        } else {
            $tagName = '';
        }
    } elseif ('' !== $tagName) {
        $tagContent .= ' '.str_replace("\t", ' ', $line);
    }
}

